package com.google.gson.reflect;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Type;

import org.junit.jupiter.api.Test;

class TypeTokenToStringTest {

  @Test
  void testToStringReturnsTypeToString() {
    // Create a TypeToken instance for String.class using the public static get method
    TypeToken<String> typeToken = TypeToken.get(String.class);

    // The expected string is the result of $Gson$Types.typeToString(type)
    // Since we have access to $Gson$Types, we use it directly
    Type type = typeToken.getType();
    String expected = com.google.gson.internal.$Gson$Types.typeToString(type);

    // Call toString and assert it matches expected
    assertEquals(expected, typeToken.toString());
  }
}
